function parseYaml(text) {
  const result = { samples: [], total: {}, data: {}, figure: {} };
  const sMatch = [...text.matchAll(/-\s*Name:\s*(.+?)\n\s*Yield:\s*\[(.+?)\]/gs)];
  for (const m of sMatch) {
    const yields = m[2].split(",").map(v => {
      v = v.trim();
      if (v === "blinded") return null;
      const n = parseFloat(v);
      return isNaN(n) ? null : n;
    });
    result.samples.push({ name: m[1].trim(), yield: yields });
  }
  const tMatch = text.match(/Total:\s*\n\s*-\s*Yield:\s*\[(.+?)\]\s*\n\s*UncertaintyUp:\s*\[(.+?)\]\s*\n\s*UncertaintyDown:\s*\[(.+?)\]/s);
  if (tMatch) {
    result.total.yield = tMatch[1].split(",").map(v => parseFloat(v.trim()));
    result.total.uncertaintyUp = tMatch[2].split(",").map(v => parseFloat(v.trim()));
    result.total.uncertaintyDown = tMatch[3].split(",").map(v => parseFloat(v.trim()));
  }
  const dMatch = text.match(/Data:\s*\n\s*-\s*Yield:\s*\[(.+?)\]/s);
  if (dMatch) {
    result.data.yield = dMatch[1].split(",").map(v => {
      v = v.trim();
      if (v === "blinded") return null;
      const n = parseFloat(v);
      return isNaN(n) ? null : n;
    });
  }
  const bMatch = text.match(/BinEdges:\s*\[(.+?)\]/s);
  if (bMatch) result.figure.binEdges = bMatch[1].split(",").map(v => parseFloat(v.trim()));
  const xMatch = text.match(/XaxisLabel:\s*(.+)/);
  if (xMatch) result.figure.xLabel = xMatch[1].trim();
  return result;
}

function parseFilename(fname) {
  const base = fname.replace(/_Run2_postfit\.yaml$/, "").replace(/\.yaml$/, "");
  if (base.startsWith("CR_")) {
    const m = base.match(/CR_(\w+)_bin(\d+)_?(\d*)_(\w+)/);
    if (m) return { regionType: "CR_" + m[1], ptBin: m[2] + "-" + (m[3] || "∞"), btagCategory: m[4], label: "CR_" + m[1] + " pT " + m[2] + "-" + (m[3] || "∞") + " " + m[4] };
  } else {
    const m = base.match(/bin(\d+)_?(\d*)_(\w+)/);
    if (m) return { regionType: "SR", ptBin: m[1] + "-" + (m[2] || "∞"), btagCategory: m[3], label: "SR pT " + m[1] + "-" + (m[2] || "∞") + " " + m[3] };
  }
  return { regionType: "unknown", ptBin: "?", btagCategory: "?", label: base };
}

