function hexRgba(hex, a) {
  return "rgba(" + parseInt(hex.slice(1,3),16) + "," + parseInt(hex.slice(3,5),16) + "," + parseInt(hex.slice(5,7),16) + "," + a + ")";
}
function fmtTick(v) {
  if (Math.abs(v) >= 1e4) return v.toExponential(0);
  if (Math.abs(v) >= 100) return Math.round(v).toString();
  if (Math.abs(v) >= 1) return Number(v.toPrecision(3)).toString();
  if (v === 0) return "0";
  return v.toExponential(0);
}
function niceStep(raw) {
  const mag = Math.pow(10, Math.floor(Math.log10(raw)));
  const n = raw / mag;
  return (n <= 1.5 ? 1 : n <= 3 ? 2 : n <= 7 ? 5 : 10) * mag;
}
function yTicksFn(mn, mx, isLog) {
  if (isLog) {
    const t = [];
    for (let e = Math.floor(Math.log10(Math.max(mn,1e-10))); e <= Math.ceil(Math.log10(mx)); e++) t.push(Math.pow(10,e));
    return t;
  }
  const step = niceStep((mx - mn) / 6);
  const t = [];
  for (let v = Math.ceil(mn / step) * step; v <= mx; v += step) t.push(v);
  return t;
}
function xTicksFn(edges) {
  if (edges.length <= 10) return edges;
  const step = Math.max(1, Math.floor(edges.length / 8));
  return edges.filter((_, i) => i % step === 0);
}

